import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../utils/api';
import Spinner from '../components/Spinner';

export default function DoctorDashboard() {
  const [stats, setStats] = useState(null);
  const [apptStats, setApptStats] = useState(null);
  const [recentAppointments, setRecentAppointments] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      api.get('/users/stats'),
      api.get('/appointments/stats'),
      api.get('/appointments?limit=5'),
    ]).then(([u, a, appts]) => {
      setStats(u.data.stats);
      setApptStats(a.data.stats);
      setRecentAppointments(appts.data.appointments);
    }).finally(() => setLoading(false));
  }, []);

  if (loading) return <Spinner />;

  const statCards = [
    { label: 'Total Patients', value: stats?.totalPatients, icon: 'bi-people', color: 'primary' },
    { label: 'Total Doctors', value: stats?.totalDoctors, icon: 'bi-person-badge', color: 'success' },
    { label: 'Pending Appointments', value: apptStats?.pending, icon: 'bi-clock', color: 'warning' },
    { label: 'Completed Today', value: apptStats?.completed, icon: 'bi-check-circle', color: 'info' },
  ];

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h4 className="mb-0">Doctor Dashboard</h4>
        <Link to="/records/new" className="btn btn-primary btn-sm">
          <i className="bi bi-plus-lg me-1" />New Record
        </Link>
      </div>

      <div className="row g-3 mb-4">
        {statCards.map((s) => (
          <div key={s.label} className="col-sm-6 col-xl-3">
            <div className={`card stat-card border-start border-${s.color} border-4`}>
              <div className="card-body d-flex justify-content-between align-items-center">
                <div>
                  <div className="text-muted small">{s.label}</div>
                  <div className="fs-3 fw-bold">{s.value ?? '—'}</div>
                </div>
                <i className={`bi ${s.icon} fs-2 text-${s.color} opacity-50`} />
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="card">
        <div className="card-header d-flex justify-content-between align-items-center">
          <span>Recent Appointments</span>
          <Link to="/appointments" className="btn btn-sm btn-outline-primary">View All</Link>
        </div>
        <div className="card-body p-0">
          <table className="table table-hover mb-0">
            <thead className="table-light">
              <tr>
                <th>Patient</th>
                <th>Date</th>
                <th>Time</th>
                <th>Reason</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {recentAppointments.length === 0 ? (
                <tr><td colSpan={5} className="text-center text-muted py-3">No appointments yet</td></tr>
              ) : recentAppointments.map((a) => (
                <tr key={a._id}>
                  <td>{a.patient?.name}</td>
                  <td>{new Date(a.date).toLocaleDateString()}</td>
                  <td>{a.timeSlot}</td>
                  <td>{a.reason}</td>
                  <td>
                    <span className={`badge badge-status-${a.status}`}>{a.status}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
